/**
 * Writes the output of `generateExamples()` (examples.mjs) to
 * website/src/generated/examples.ts as a plain data literal — the single
 * source `<Terminal>` reads from (F11 AC4). Regenerated by
 * `npm run docs:examples`; tests/integration/docs-examples.test.ts asserts
 * the committed file matches a fresh run byte-for-byte.
 *
 * Usage: `node website/scripts/generate-examples.mjs` (npm run docs:examples)
 */
import { writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { generateExamples } from "./examples.mjs";

const OUT_FILE = fileURLToPath(new URL("../src/generated/examples.ts", import.meta.url));

const HEADER = `// GENERATED FILE — do not hand-edit.
//
// Produced by \`npm run docs:examples\` (website/scripts/examples.mjs +
// generate-examples.mjs), which spawns the real built \`dist/cli.js\` against
// real temp git repos and writes its exact output here (F11 AC4 — "no stale
// or invented output, ever"). tests/integration/docs-examples.test.ts
// regenerates this file on every CI run and fails the build if it drifts
// from what's committed.

export interface GeneratedExample {
  command: string;
  output: string;
  style: "terminal" | "code";
}
`;

/** JSON.stringify already produces valid (if minified) JS/TS object syntax;
 * indenting by 2 keeps the generated file diff-reviewable in PRs. */
export function renderModule(examples) {
  const entries = [...examples.entries()]
    .map(([name, example]) => `  ${JSON.stringify(name)}: ${JSON.stringify(example, null, 2).replace(/\n/g, "\n  ")},`)
    .join("\n");
  return `${HEADER}\nexport const EXAMPLES: Record<string, GeneratedExample> = {\n${entries}\n};\n`;
}

async function main() {
  const examples = await generateExamples();
  await writeFile(OUT_FILE, renderModule(examples));
  console.log(`docs examples: wrote ${examples.size} examples to ${OUT_FILE}`);
}

main().catch((err) => {
  console.error(err instanceof Error ? err.message : String(err));
  process.exit(1);
});
